# Scheduling visualization of 1F1B Pipeline Parallelism
def simulate_1f1b_schedule(stages=4, microbatches=8):
    # Output logs showing execution order
    timeline = []
    for mb in range(microbatches):
        for stage in range(stages):
            time_slot = mb + stage
            timeline.append(f"MB {mb} FWD on Stage {stage} at slot {time_slot}")
    # Simulating backward passes which start as soon as FWD reaches final stage
    return timeline[:20]  # First 20 operations

import torch.utils.checkpoint as checkpoint

# Conceptual representation of checkpointing layers
class DenseBlock(nn.Module):
    def __init__(self):
        super().__init__()
        self.layers = nn.Sequential(nn.Linear(1024, 1024), nn.ReLU(), nn.Linear(1024, 1024))

    def forward(self, x):
        return self.layers(x)

class CheckpointedModel(nn.Module):
    def __init__(self):
        super().__init__()
        self.blocks = nn.ModuleList([DenseBlock() for _ in range(8)])
        self.use_checkpointing = True

    def forward(self, x):
        for block in self.blocks:
            if self.use_checkpointing and x.requires_grad:
                # Recomputes this block's activations during backward pass
                x = checkpoint.checkpoint(block, x, use_reentrant=False)
            else:
                x = block(x)
        return x
